import{_ as o,o as i,c as t,aj as a}from"./chunks/framework.DEEoir6m.js";const u=JSON.parse('{"title":"Changelog","description":"GISPulse version history.","frontmatter":{"title":"Changelog","description":"GISPulse version history."},"headers":[],"relativePath":"en/changelog.md","filePath":"en/changelog.md"}'),r={name:"en/changelog.md"};function s(l,e,n,d,c,g){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes are documented here. Format based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>. Versioning follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong>Capabilities reference</strong> — bumped from <strong>78 to 117</strong> documented capabilities (FR + EN), 11 → 18 categories. New sections: vector overlay &amp; combine, attribute manipulation, pivot/unpivot, ordered selection &amp; sampling, multipart &amp; Z/M dimensions, geometric transforms, boundary &amp; projection, temporal, 3D pointcloud.</li><li><strong>Playground manifest</strong> — regenerated with the <strong>6 scenarios</strong> actually deployed (S1 flood-risk, S2 data-quality, S3 accessibility, S4 road-setback, S5 green-spaces, S6 real-estate). The previous manifest only listed <code>road-setback</code>.</li><li><strong>Idempotent playground build</strong> — <code>scripts/build_playground_data.py</code> gains <code>_entry_from_disk</code>: emits a manifest entry from existing files when the source GPKG is missing.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>CHANGELOG v1.1.0</strong> — corrected: S5 is described as &quot;Park accessibility&quot; (not &quot;Canopy typology&quot;), the &quot;S7 / seven-scenario index&quot; claim is removed since that page never shipped.</li><li><strong>Orphan pages</strong> — <code>playground/environmental-ndvi.md</code> (FR + EN) deleted: outdated JS redirects, no remaining source references.</li></ul><h3 id="removed" tabindex="-1">Removed <a class="header-anchor" href="#removed" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li><strong>S7 dvf-heavy-tail scenario</strong> — spec dropped from the build script; the orphan data folder has been removed. The scenario page never existed in the docs.</li></ul><hr><h2 id="_1-1-1-—-2026-04-25" tabindex="-1">[1.1.1] — 2026-04-25 <a class="header-anchor" href="#_1-1-1-—-2026-04-25" aria-label="Permalink to &quot;[1.1.1] — 2026-04-25&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong><code>capabilities/vector/</code></strong> — the monolithic <code>vector.py</code> (4,359 LOC, 43 capabilities) was split into a 32-module per-domain package. The public surface is preserved through a re-export shim; every <code>from capabilities.vector import ...</code> keeps working unchanged.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong><code>gispulse/__init__.py</code></strong> — fallback <code>__version__</code> changed from hardcoded <code>&quot;1.0.0&quot;</code> to <code>&quot;unknown&quot;</code> when <code>importlib.metadata</code> is unavailable.</li><li><strong><code>portal/package.json</code></strong> + <strong><code>docs-site/package.json</code></strong> — versions synced to <code>1.1.1</code> to match <code>pyproject.toml</code>.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Accessibility</strong> — keyboard navigation on <code>PipelinePanel</code>, portal imports unified around design-system tokens.</li></ul><hr><h2 id="_1-1-0-—-2026-04-25" tabindex="-1">[1.1.0] — 2026-04-25 <a class="header-anchor" href="#_1-1-0-—-2026-04-25" aria-label="Permalink to &quot;[1.1.0] — 2026-04-25&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Playground scenarios</strong> — S5 Park accessibility (Versailles, BD TOPO vegetation ≥ 1 ha + <code>nearest_neighbor</code> + <code>classify</code>, weekly cron) and S6 Price-per-m² DVF map (8 steps, 50 m fishnet, YlOrRd quintiles).</li><li><strong>Capabilities — classification &amp; stats</strong> — <code>head_tail_breaks</code> (Jiang 2013), <code>normalize</code> (log1p / minmax / zscore), <code>grid_create</code>, <code>hexgrid_create</code>, <code>spatial_aggregate</code>, <code>classify_categorical</code>, <code>bivariate_choropleth</code>, <code>graduated_size</code>, <code>continuous_ramp</code>, <code>kde_heatmap</code>. Clustering: <code>cluster_kmeans</code>, <code>cluster_dbscan</code>, <code>cluster_hdbscan</code>, <code>morans_i</code>, <code>getis_ord_g</code>, <code>nearest_neighbor</code>, <code>od_matrix</code>, <code>spatial_weights</code>.</li><li><strong>Capabilities — 3D pointcloud</strong> — LAS / LAZ sprint: <code>pointcloud_load_las</code>, <code>pointcloud_filter_classification</code>, <code>pointcloud_zonal_height</code>, <code>pointcloud_grid_summary</code>.</li><li><strong>Capabilities — layer manipulation P0-P3</strong> — overlay (<code>overlay_intersection</code>, <code>overlay_union</code>, <code>erase</code>), selection (<code>sort</code>, <code>deduplicate</code>, <code>random_sample</code>, <code>top_n</code>), shape ops, transforms (<code>affine_transform</code>, <code>swap_xy</code>, <code>reverse_lines</code>), Z/M (<code>add_z</code>, <code>drop_z</code>, <code>add_m</code>, <code>drop_m</code>), pivot/unpivot, <code>classify_by_ring</code>, <code>merge_layers</code>, attribute logic (<code>add_field</code>, <code>drop_field</code>, <code>select_columns</code>, <code>rename_field</code>, <code>cast_field</code>, <code>attribute_join</code>, <code>lookup_table</code>, <code>coalesce_fields</code>, <code>case_when</code>), temporal (<code>temporal_filter</code>, <code>temporal_join</code>).</li><li><strong>Playground UX</strong> — rubber-band drawing with snap-to-close + keyboard shortcuts + live measurement; client-side polygon intersection styling (S4 road-setback).</li><li><strong>DVF Etalab 2022-2024</strong> — sample dataset bundled with <code>examples/prepare_playground_data.py --city versailles</code> (<code>dvf_ventes</code> layer).</li><li><strong>Style sidecars</strong> — <code>.style.qml</code> / <code>.style.sld</code> / <code>.legend.json</code> files emitted next to vector outputs for direct QGIS / GeoServer import.</li><li><strong>SQL preview</strong> — explicit auth gate + capability blocklist on the PostGIS SQL capability.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><strong><code>core/config.py</code></strong> — centralised all environment variables into a single Pydantic Settings module (13 groups: <code>engine</code>, <code>database</code>, <code>storage</code>, <code>s3</code>, <code>api</code>, <code>oidc</code>, <code>session</code>, <code>redis</code>, <code>logging</code>, <code>audit</code>, <code>stripe</code>, <code>telemetry</code>, <code>jobs</code>). Backward-compatible with every existing <code>GISPULSE_*</code> name.</li><li><strong>Default engine</strong> — changed from <code>duckdb</code> to <code>gpkg</code> (portable GPKG / GeoPandas mode).</li><li><strong>Removed scattered <code>os.environ.get()</code> calls</strong> — routers, adapters, persistence: everything routes through <code>settings</code>.</li><li><strong>Playground S5</strong> rewritten as park accessibility per building — BD TOPO vegetation ≥ 1 ha (SCoT IdF), <code>nearest_neighbor</code> distance building → park, classified against OMS / SCoT / ADEME thresholds (300 / 600 / 1000 m). The former NDVI / canopy trigger has been dropped.</li><li><strong>Playground S6</strong> extended to a 250 m then tightened to a 50 m fishnet choropleth for high-resolution heatmap rendering.</li><li><strong>Playground S3</strong> — 6-step pipeline collapsed to 3 via <code>cost_budgets</code> + <code>classify_by_ring</code> (4 concentric isochrones 500 / 750 / 1000 / 1500 m).</li><li><strong><code>adapters/http</code></strong> — namespace fork resolved: legacy tree deleted, prod entrypoints flipped to <code>gispulse.adapters.http.app</code>.</li><li><strong>Security</strong> — <code>MD5</code> replaced by <code>BLAKE2b</code>, <code>eval</code> sandboxed for <code>np</code>, <code>_ensure_valid</code> restored.</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Capabilities — 4 P0 closed</strong>: <code>force_geometry_type</code> (GeometryCollection target), <code>attribute_join</code> on a plain DataFrame, NaN crash in the <code>add_z</code> / <code>add_m</code> <code>from_column</code> path, <code>singleparts_to_multipart</code> silent data loss on mixed geom types.</li><li><strong>Capabilities</strong> — pointcloud grid 2D NaN, KDE grid blow-up, <code>Calculate</code> RCE sandbox.</li><li><strong>Tests</strong> — repaired 27 tests once CI was unblocked, removed shadow <code>__init__.py</code>, enabled <code>asyncio_mode = &quot;auto&quot;</code>, fixed <code>workflows/ftth_network_analysis.py</code> SyntaxError. 3,600+ tests green.</li><li><strong>Tests</strong> — isolate <code>GISPULSE_ENGINE</code> mutations; conftest auth-disabled-by-default.</li><li><strong>Billing</strong> — default <code>StripeSettings</code> + actionable error messages when Stripe keys are missing.</li><li><strong>Capabilities</strong> — <code>clip</code> / <code>intersects</code> no longer evaluate <code>GeoDataFrame</code> truthiness; <code>spatial_predicate</code> fallback made explicit.</li><li><strong>Playground</strong> — S6 <code>drop_price_outliers</code> renamed to <code>drop_value_outliers</code> (filters the raw <code>valeur_fonciere</code>, not price-per-m²).</li><li><strong>i18n</strong> — <code>PipelinePanel</code> strings; default-engine alignment; pipelines <code>ref_layers</code> plural.</li><li><strong>Performance</strong> — lazy-loaded <code>DualMapView</code>.</li><li><strong>Rules router</strong> — payload validation before persisting (400 with structured errors).</li></ul><hr><h2 id="_1-0-2-—-sprint-s1→s6-2026-04-12" tabindex="-1">[1.0.2] — Sprint S1→S6 (2026-04-12) <a class="header-anchor" href="#_1-0-2-—-sprint-s1→s6-2026-04-12" aria-label="Permalink to &quot;[1.0.2] — Sprint S1→S6 (2026-04-12)&quot;">​</a></h2><p>Six sprints of audit and hardening: security, architecture, tests, observability, router coverage, Prometheus metrics.</p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="architecture-—-declarative-grammar-v2-sprint-s1" tabindex="-1">Architecture — Declarative Grammar v2 (Sprint S1) <a class="header-anchor" href="#architecture-—-declarative-grammar-v2-sprint-s1" aria-label="Permalink to &quot;Architecture — Declarative Grammar v2 (Sprint S1)&quot;">​</a></h4><ul><li><strong><code>PipelineSpec</code> / <code>StepSpec</code> / <code>TriggerSpec</code></strong> — unified grammar replacing 3 divergent DSLs</li><li><strong>DAG support</strong> — steps can reference other steps via <code>step.input</code></li><li><strong>Conditional steps</strong> — <code>step.when</code> predicate evaluation on current GeoDataFrame</li><li><strong>Inline triggers</strong> — <code>on/when/then</code> syntax within pipelines</li><li><strong>Backward-compatible</strong> — v1 flat rule lists auto-converted to v2</li><li><strong><code>PipelineExecutor</code></strong> — unified executor (linear and DAG mode via <code>GraphExecutor</code>)</li><li><strong><code>PluginRegistry[T]</code></strong> — generic thread-safe registry with entry point discovery</li></ul><h4 id="pipeline-v2-api-sprint-s2" tabindex="-1">Pipeline v2 API (Sprint S2) <a class="header-anchor" href="#pipeline-v2-api-sprint-s2" aria-label="Permalink to &quot;Pipeline v2 API (Sprint S2)&quot;">​</a></h4><ul><li><strong><code>POST /api/pipelines/execute</code></strong> — execute v2 pipelines with <code>PipelineSpec</code> JSON</li><li><strong><code>POST /api/pipelines/validate</code></strong> — dry-run pipeline validation</li><li><strong><code>GET /api/pipelines/examples</code></strong> — v2 pipeline examples</li><li><strong>CRUD <code>/api/triggers/{id}/operations</code></strong> — spatial operations persistence in triggers</li><li><strong><code>SessionManager.run_pipeline_v2()</code></strong> — native delegation to <code>PipelineExecutor</code></li><li><strong>TypedDict for 10 capabilities</strong> — <code>FilterParams</code>, <code>BufferParams</code>, etc.</li><li><strong>PipelineEditor</strong> — portal editor mode: import/export v2 JSON, execute via <code>/pipelines/execute</code></li></ul><h4 id="portal-—-decomposition-websocket-sprint-s3" tabindex="-1">Portal — Decomposition &amp; WebSocket (Sprint S3) <a class="header-anchor" href="#portal-—-decomposition-websocket-sprint-s3" aria-label="Permalink to &quot;Portal — Decomposition &amp; WebSocket (Sprint S3)&quot;">​</a></h4><ul><li><strong><code>LayerItemButton</code></strong> and <strong><code>DatasetItem</code></strong> extracted from <code>LeftPanel.tsx</code> (1183→774 lines)</li><li><strong>WebSocket listener</strong> replaces <code>setInterval</code> polling in <code>transformStore</code></li><li><strong>CI GitHub Actions</strong> — <code>ci.yml</code> workflow with backend (pytest, ruff) and frontend (tsc, vite build) jobs</li></ul><h4 id="documentation-tooling-sprint-s4" tabindex="-1">Documentation &amp; Tooling (Sprint S4) <a class="header-anchor" href="#documentation-tooling-sprint-s4" aria-label="Permalink to &quot;Documentation &amp; Tooling (Sprint S4)&quot;">​</a></h4><ul><li><strong><code>scripts/export_openapi.py</code></strong> — auto-generates <code>docs/openapi.json</code> + <code>docs/API_REFERENCE.md</code></li><li><strong>QUICKSTART.md</strong>, <strong>RULES_GUIDE.md</strong>, <strong>TRIGGERS_GUIDE.md</strong>, <strong>API_QUICKSTART.md</strong> — 4 user guides</li><li><strong><code>docs/openapi.json</code></strong> — complete OpenAPI 3.1 specification (88 endpoints)</li></ul><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><h4 id="models-sprint-s1" tabindex="-1">Models (Sprint S1) <a class="header-anchor" href="#models-sprint-s1" aria-label="Permalink to &quot;Models (Sprint S1)&quot;">​</a></h4><ul><li><strong><code>core/models.py</code> split</strong> (795→280L) into 6 modules: <code>enums.py</code>, <code>conditions.py</code>, <code>predicates.py</code>, <code>graph.py</code>, <code>relations.py</code>, <code>session.py</code></li><li><strong><code>Rule.order</code></strong> extracted from config bag to dedicated field</li></ul><h4 id="portal-sprint-s3" tabindex="-1">Portal (Sprint S3) <a class="header-anchor" href="#portal-sprint-s3" aria-label="Permalink to &quot;Portal (Sprint S3)&quot;">​</a></h4><ul><li><strong>Predicate type renaming</strong> — removed <code>*Node</code> suffix (<code>AttrPredicateNode</code> → <code>AttrPredicate</code>)</li><li><strong>Forge operations connected</strong> — <code>OperationExecutor</code> → ESB: <code>RUN_SQL</code> actions run end-to-end</li></ul><h3 id="removed-1" tabindex="-1">Removed <a class="header-anchor" href="#removed-1" aria-label="Permalink to &quot;Removed&quot;">​</a></h3><ul><li><strong>Non-functional client stubs</strong> — <code>clients/qgis/</code>, <code>clients/arcgis/</code>, <code>clients/desktop/</code> (code in git history)</li><li><strong>ESB <code>CircuitBreaker</code> and <code>DeadLetterQueue</code></strong> marked <code>EXPERIMENTAL</code>, lazy-import only</li></ul><h3 id="security-sprint-s1" tabindex="-1">Security (Sprint S1) <a class="header-anchor" href="#security-sprint-s1" aria-label="Permalink to &quot;Security (Sprint S1)&quot;">​</a></h3><ul><li>Patch for 13 critical vulnerabilities (7 SQL injections, 2 RCE, 1 auth bypass)</li><li>114 security tests covering all audit vectors</li><li><strong><code>hmac.compare_digest()</code></strong> for all auth comparisons (timing-safe)</li><li><strong>Nginx security headers</strong> — CSP, X-Frame-Options DENY, X-Content-Type-Options nosniff, Referrer-Policy</li><li><strong>Rate limiting</strong> on <code>/api/filter/preview</code> (30/min) and <code>/api/filter/apply</code> (20/min)</li><li><strong><code>pip-audit</code></strong> now blocks CI on known CVEs (removed <code>|| true</code>)</li><li><strong>Upload size validation</strong> — handles invalid env values, caps at 5GB</li></ul><h3 id="architecture-sprint-s2" tabindex="-1">Architecture (Sprint S2) <a class="header-anchor" href="#architecture-sprint-s2" aria-label="Permalink to &quot;Architecture (Sprint S2)&quot;">​</a></h3><ul><li><strong>structlog migration</strong> — replaced <code>print()</code> and stdlib <code>logging</code> with structlog in ESB workers and pg_notify</li><li><strong>Silent exception logging</strong> — 6 <code>except: pass</code> handlers replaced with <code>log.debug()</code>/<code>log.warning()</code></li><li><strong>Job cancellation race fix</strong> — check cancellation BEFORE persisting results</li><li><strong>Dataset load timeout</strong> — 300s max to prevent hangs on large files</li><li><strong>Trigger name collision fix</strong> — use trigger UUID as suffix (supports multiple triggers per table)</li><li><strong>WebSocket message limit</strong> — 1MB max per outgoing message</li></ul><h3 id="observability-sprint-s4-s6" tabindex="-1">Observability (Sprint S4 + S6) <a class="header-anchor" href="#observability-sprint-s4-s6" aria-label="Permalink to &quot;Observability (Sprint S4 + S6)&quot;">​</a></h3><ul><li><strong><code>MetricsMiddleware</code></strong> — automatic HTTP metrics: <code>gispulse_http_requests_total</code>, <code>gispulse_http_request_duration_seconds</code>, <code>gispulse_http_requests_in_flight</code></li><li><strong>Path normalization</strong> — collapses UUIDs and numeric segments to reduce Prometheus cardinality</li><li><strong>Trace ID correlation</strong> — <code>trace_id</code> in structured error logs for incident investigation</li><li><strong>Docker non-root</strong> — <code>USER appuser</code> (uid 1000) in Dockerfile</li><li><strong><code>.dockerignore</code></strong> — excludes .git, node_modules, tests, docs, .env, IDE files</li><li><strong><code>.pre-commit-config.yaml</code></strong> — ruff lint+format, trailing whitespace, YAML check, private key detection</li></ul><h3 id="tests-sprints-s3-s5" tabindex="-1">Tests (Sprints S3 + S5) <a class="header-anchor" href="#tests-sprints-s3-s5" aria-label="Permalink to &quot;Tests (Sprints S3 + S5)&quot;">​</a></h3><ul><li><strong>2,439 tests</strong> passing (up from 2,205 in v1.0.1), +234 tests across 6 sprints</li><li><strong>106 test files</strong> (unit + integration + security)</li><li><strong>Router coverage: 85%</strong> (23/27 routers tested, up from 33%)</li><li>16 new test files covering rules, triggers, jobs, datasets, CLI, persistence IO, auth, admin, scenarios, schedules, catalog, relations, filter, portal, ESB, tiles</li><li><strong>CI: mypy</strong> (type checking core modules) + <strong>ESLint/Vitest</strong> (frontend lint + tests)</li></ul><hr><h2 id="_1-0-0-—-2026-04-06" tabindex="-1">[1.0.0] — 2026-04-06 <a class="header-anchor" href="#_1-0-0-—-2026-04-06" aria-label="Permalink to &quot;[1.0.0] — 2026-04-06&quot;">​</a></h2><p>Initial public release. 27 capabilities, 1,836 tests, multi-backend DuckDB/PostGIS engine.</p><hr><h2 id="_0-1-0-—-2026-03-31" tabindex="-1">[0.1.0] — 2026-03-31 <a class="header-anchor" href="#_0-1-0-—-2026-03-31" aria-label="Permalink to &quot;[0.1.0] — 2026-03-31&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="core-engine" tabindex="-1">Core engine <a class="header-anchor" href="#core-engine" aria-label="Permalink to &quot;Core engine&quot;">​</a></h4><ul><li>DuckDB geospatial engine with portable SpatiaLite and persistent PostGIS modes</li><li><code>SessionManager</code> with E2E pipeline, <code>ExecutionStrategy</code> pattern, SpatiaLite session support</li><li><code>JobRunner</code> with async execution and job status tracking</li><li>Cross-layer operations: spatial join, reference layer system, multi-layer support</li><li>Pagination, dataset association, project CRUD</li><li>PyOGRIO migration for multi-format I/O</li><li>Edge case hardening: shadow zones, centroid, area/length capabilities</li><li>GeoParquet support and OGC server with MVT tile server</li></ul><h4 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h4><ul><li>Typer CLI entry point (<code>gispulse</code>)</li><li>Commands: <code>init</code>, <code>validate</code>, <code>info</code>, <code>layers</code>, <code>formats</code>, <code>capabilities</code>, <code>serve</code>, <code>portal</code>, <code>doctor</code></li><li>Multi-format acceptance via the integrated I/O layer</li></ul><h4 id="vector-capabilities-10" tabindex="-1">Vector capabilities (10) <a class="header-anchor" href="#vector-capabilities-10" aria-label="Permalink to &quot;Vector capabilities (10)&quot;">​</a></h4><ul><li><code>buffer</code> — metric buffer with automatic reprojection</li><li><code>union</code> — merge all features</li><li><code>reproject</code> — CRS reprojection</li><li><code>filter</code> — attribute filter</li><li><code>clip</code> — clip by reference layer</li><li><code>intersects</code> — filter by spatial intersection</li><li><code>spatial_join</code> — spatial join</li><li><code>centroid</code> — centroid extraction</li><li><code>area_length</code> — area and length calculation</li><li><code>dissolve</code> — dissolve by attribute</li><li>Capability registry with auto-discovery</li><li>Lifespan-managed capability injection</li></ul><h4 id="rules" tabindex="-1">Rules <a class="header-anchor" href="#rules" aria-label="Permalink to &quot;Rules&quot;">​</a></h4><ul><li>Rules-as-config system with JSON definitions</li><li>Rule editor UI with predicate builder</li><li>Trigger-based rule evaluation with <code>auto_eval</code> and SSE eval-stream</li></ul><h4 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h4><ul><li>Persistent PostGIS mode with live sync and pg_notify integration</li><li>Portable SpatiaLite mode (level 2 session, serverless)</li><li>GPKG export from catalog</li><li>Scene manager with snapshot and restore</li></ul><h4 id="rest-api-fastapi" tabindex="-1">REST API (FastAPI) <a class="header-anchor" href="#rest-api-fastapi" aria-label="Permalink to &quot;REST API (FastAPI)&quot;">​</a></h4><ul><li>Full REST API: projects, datasets, features, sessions, rules, triggers, scenarios</li><li>14 routers, 100+ endpoints</li><li>Feature update, SQL execution, relation endpoints</li><li>OGC Features ingestion endpoints</li><li>SSE streaming for trigger evaluation results</li><li>Docker hot-reload configuration for API and Portal dev servers</li><li>Global error handlers <code>{&quot;error&quot;: {&quot;code&quot;, &quot;message&quot;, &quot;detail&quot;}}</code> for 400/404/422/500</li></ul><h4 id="portal-react-19" tabindex="-1">Portal (React 19) <a class="header-anchor" href="#portal-react-19" aria-label="Permalink to &quot;Portal (React 19)&quot;">​</a></h4><ul><li>5-workspace layout: Explorer, Map, Workflows, Catalog, Data</li><li>Layer tree with groups, color picker, legend and symbology</li><li>Resizable panel layout with ActivityBar and Inspector</li><li>Node editor (XyFlow/ReactFlow v12) with 9 node types, NodePalette, inline inspector</li><li>Trigger stepper, scenario bar, spatial operations UI</li><li>SQL console and feature inspector</li><li>Catalog workspace with cards, favorites, mini-map, domain filtering</li><li>Dark mode with OKLCH design tokens, Geist font, toast notifications</li><li>Command palette (Ctrl+K), keyboard shortcuts (1–5, Ctrl+I/B/K/S/?)</li><li>Drag-and-drop upload and URL import, GPKG export with QML styles</li></ul><h4 id="viewer" tabindex="-1">Viewer <a class="header-anchor" href="#viewer" aria-label="Permalink to &quot;Viewer&quot;">​</a></h4><ul><li>Embedded deck.gl spatial viewer served via <code>gispulse serve</code></li></ul><h4 id="esb-triggers" tabindex="-1">ESB / Triggers <a class="header-anchor" href="#esb-triggers" aria-label="Permalink to &quot;ESB / Triggers&quot;">​</a></h4><ul><li>Event bus with pg_notify, routing, circuit breaker, dead letter queue</li><li>Trigger Builder UI with predicate composition</li><li><code>SessionProvisioner</code> with <code>TriggerEvaluator</code> and SSE eval-stream</li></ul><h4 id="catalog" tabindex="-1">Catalog <a class="header-anchor" href="#catalog" aria-label="Permalink to &quot;Catalog&quot;">​</a></h4><ul><li>GIS data catalog: projections, basemaps, WMS/WFS feeds, open data sources</li></ul><h4 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h4><ul><li>46 test files: unit and integration</li><li>SpatiaLite E2E integration tests</li><li>Pytest configuration with async support</li></ul><hr><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li><a href="https://github.com/gispulse/gispulse" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://github.com/gispulse/gispulse/issues" target="_blank" rel="noreferrer">Report a bug</a></li><li><a href="https://github.com/gispulse/gispulse/projects" target="_blank" rel="noreferrer">Roadmap</a></li></ul>',83)])])}const h=o(r,[["render",s]]);export{u as __pageData,h as default};
